#include <stdio.h>
#include <string.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N; scanf("%d", &N);
        char s[100005]; scanf("%s", s);
        int cnt=0;
        for(int i=0;i<N-1;i++) if(s[i]!=s[i+1]) cnt++;
        int ans = (cnt+1)/2;
        printf("%d\n", ans);
    }
    return 0;
}

