const fs = require('fs');
const input = fs.readFileSync(0, 'utf-8').trim().split(/\s+/);
let idx = 0;
const T = Number(input[idx++]);
let results = [];
for (let tc = 0; tc < T; tc++) {
  const N = Number(input[idx++]);
  const s = input[idx++];
  let cnt = 0;
  for (let i = 0; i < N - 1; i++) {
    if (s[i] !== s[i + 1]) cnt++;
  }
  const ans = Math.floor((cnt + 1) / 2);
  results.push(String(ans));
}
console.log(results.join('\n'));
